import Link from "next/link";
import { AppShell } from "@/components/app-shell";
import { getAuthContext } from "@/lib/firebase/auth";
import { boardsRepository } from "@/lib/repositories/boards-repository";
import { knowledgeRepository } from "@/lib/repositories/knowledge-repository";
import { skillsRepository } from "@/lib/repositories/skills-repository";

export default async function Page() {
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell title="Dashboard"><p>Sessão não encontrada.</p></AppShell>;
  }

  const [boards, knowledge, skills] = await Promise.all([
    boardsRepository.list(auth.workspaceId),
    knowledgeRepository.list(auth.workspaceId),
    skillsRepository.list(auth.workspaceId),
  ]);

  return (
    <AppShell title="Dashboard">
      <div className="content-stack space-y-6">
        <section className="stat-grid">
          <article className="app-card"><p className="eyebrow">Board items</p><p className="stat-value">{boards.length}</p></article>
          <article className="app-card"><p className="eyebrow">Knowledge entries</p><p className="stat-value">{knowledge.length}</p></article>
          <article className="app-card"><p className="eyebrow">Skills</p><p className="stat-value">{skills.length}</p></article>
        </section>
        <section className="app-card">
          <h2 className="mb-3 font-semibold">Acessos rapidos</h2>
          <div className="quick-links">
            <Link href="/board" className="pill-link">Board</Link>
            <Link href="/knowledge" className="pill-link">Knowledge</Link>
            <Link href="/skills" className="pill-link">Skills</Link>
          </div>
        </section>
        <section className="two-column">
          <article className="app-card">
            <h2 className="mb-3 font-semibold">Atividade recente</h2>
            {boards.slice(0, 4).map((item) => (
              <p key={item.id} className="text-sm muted">{item.title}</p>
            ))}
            {boards.length === 0 ? <p className="text-sm muted">Sem atividade recente.</p> : null}
          </article>
          <article className="app-card">
            <h2 className="mb-3 font-semibold">Top skills</h2>
            {skills.slice(0, 5).map((skill) => (
              <span key={skill.id} className="tag-pill">{skill.name}</span>
            ))}
            {skills.length === 0 ? <p className="text-sm muted">Nenhuma skill cadastrada.</p> : null}
          </article>
        </section>
      </div>
    </AppShell>
  );
}
